INSERT INTO `news` VALUES (1, 'Tác giả Attack on Titan hé lộ những sự thật lần đầu kể với báo chí!', 'https://s199.imacdn.com/ta/2023/01/27/f0e67b20a19d3b09_c069f3ced77e2de6_3235316748253069185710.jpg', NULL, '<div class=\"news-content\">\n				                                                                                                                <p><b>Trong một cuộc phỏng vấn mới đây của Radio France, một đài phát thanh công cộng quốc gia của Pháp với tác giả của bộ truyện tranh Attack on Titan Hajime Isayama về việc các nguồn cảm hứng đầu sau tác phẩm ăn khách của ông.</b></p><p><br></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/9ebc8959b3286ba1_c45ae58871910b32_7702316748248096185710.jpg\" style data-filename=\"filename\"></p><p><br></p><p>Về nội dung của bộ truyện, tác giả đã giải thích quê hương của bản thân Hita - Nhật Bản, được bao quanh bởi những ngọn núi đã khiến anh cảm thấy như phải sống biệt lập trên một hoang đảo. Chính từ cảm giác này đã dẫn dắt anh tạo nên câu chuyện trong Attack on Titan.</p><p><br></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/3f56f37d68b7adb2_4ac239303c89790a_9156416748249803185710.jpg\" data-filename=\"filename\" style></p><p><br></p><p>Trong một cuộc phỏng vấn cùng với nhà báo Liban Léa Salamé, người đã so sánh Attack on Titan với triết lý của Thomas Hobbes với câu nói \"Con người chính là sói đối với con người\". Isayama sau đó cũng đã thừa nhận ý tưởng này đã xuất hiện trong tác phẩm, nhưng nguồn cảm hứng lại đến từ kinh nghiệm làm việc ở một quán cà phê. Tác giả đã cho biết bản thân cảm thấy rất lo lắng khi mà khách hàng trở nên hung hăng.</p><p>Nhắc đến Eren, nhân vật chính trong tác phẩm, nguyên tác Isayama đã khẳng định nhân vật chính là \"phần tồi tệ nhất\" của bản thân và bộ truyện là hành trình loại bỏ những phần tồi tệ ấy khỏi con người ấy. Anh chia sẻ bản thân đã cảm thấy hơi tệ sau khi hoàn thành bộ truyện nhưng rất hài lòng với nó.</p><p><br></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/7c622f7613b15115_358894be6faaf206_6930416748251234185710.jpg\" data-filename=\"filename\" style><br></p><p>Tác giả cũng xác nhận hiện tại, anh không có ý định làm phần tiếp theo của Attack on Titan cũng như một manga khác. Thay vào đó, anh sẽ mở một phòng tắm hơi theo ước mơ của mình.</p><p><br></p><p>Anime: <a href=\"https://vuighe.net/attack-on-titan\" target=\"_blank\">https://vuighe.net/attack-on-titan</a></p><p>Manga: <a href=\"https://truyenday.com/attack-on-titan\" target=\"_blank\">https://truyenday.com/attack-on-titan</a>&nbsp;</p>\n                                                    \n                                                    \n\n\n\n			</div>', 'tac-gia-attack-on-titan-he-lo-nhung-su-that-lan-dau-ke-voi-bao-chi', 'https://tinanime.com/tac-gia-attack-on-titan-he-lo-nhung-su-that-lan-dau-ke-voi-bao-chi', '2023-02-07 16:41:15', '2023-02-07 16:41:15');
INSERT INTO `news` VALUES (2, 'Một bộ anime chuyển giới mùa Đông 2023 đã tạo nên làn sóng tranh cãi!?', 'https://s199.imacdn.com/ta/2023/01/27/903dd8ebef675294_5669c3de9d210cb6_3991316748262213185710.jpg', NULL, '<div class=\"news-content\">\n				                                                        <p><b>Một mùa anime mới, Anime mùa Đông 2023 đã bắt đầu diễn ra và những tác phẩm anime hài vẫn luôn nhận được sự quan tâm của cộng đồng mạng. Nhưng mới nhất chính là Onii-chan wa Oshimai!, một bộ anime hài mang chủ đề chuyển giới do studio Bind sản xuất. Tuy nhiên, sê-ri này đang vấp phải phản ứng dữ dội trên mạng xã hội vì nhiều lý do.</b></p><p><br></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/6711cab17ee062a2_911207c7c937bb4e_6493416748258431185710.jpg\" style data-filename=\"filename\"></p><p><br></p><p>Lý do dẫn đến chỉ trích tác phẩm thực chất không phải đến từ việc chất lượng hoạt hình kém hay là nội dung không hấp dẫn mà là sự thất vọng của khán giả khi hình ảnh chuyển giới trong anime luôn bị gợi dục hóa.&nbsp;</p><p>Nhiều người dùng trên Twitter đã để lại bình luận như:</p><p> \"Trời ơi, không thể có bất kỳ hình thức chuyển giới nào mà không bị giới tính hóa sao?\"</p><p>\"Đây chả phải là điều mà người hâm mộ muốn\"</p><p>\"Đây chính là lý do mà tôi chả bao giờ muốn xem anime\".</p><p><br></p><div id=\"ta-179819\" class=\"player note-video-clip\"><div class=\"player-big-play-button\"><i class=\"fa fa-play\"></i></div></div><p style=\"text-align: center; \"><i>Đoạn nhạc mở đầu đầy phân cảnh gợi dục, phản cảm.</i></p><p><br></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/12d637e94f9bbe72_da9801b105172e50_7343216748261484185710.jpg\" style data-filename=\"filename\"></p><p><br></p><p>Có vẻ như điều mà người hâm mộ đang chờ đón không phải những trò đùa \"ecchi đến mức thô thiển\" này.</p><p><br></p><p>Anime: <a href=\"https://vuighe.net/oniichan-wa-oshimai\" target=\"_blank\">https://vuighe.net/oniichan-wa-oshimai</a></p><p>Manga: <a href=\"https://truyenday.com/oniichan-wa-oshimai\" target=\"_blank\">https://truyennhanh1.com/oniichan-wa-oshimai</a></p>\n                                                    </p>\n                                                    \n\n\n\n			</div>', 'mot-bo-anime-chuyen-gioi-mua-dong-2023-da-tao-nen-lan-song-tranh-cai', 'https://tinanime.com/mot-bo-anime-chuyen-gioi-mua-dong-2023-da-tao-nen-lan-song-tranh-cai', '2023-02-07 16:41:15', '2023-02-07 16:41:15');
INSERT INTO `news` VALUES (3, 'Giả thuyết về kịch bản kết thúc của One Piece khiến netizen náo loạn!', 'https://s199.imacdn.com/ta/2023/01/27/d290f21ceac6cf33_d67f2b20a19c0a7a_5615616748295854185710.jpg', NULL, '<div class=\"news-content\">\n				                                                                                                                <p><b>Đã hơn 20 năm kể từ khi bộ truyện tranh One Piece được bắt đầu và đến nay, chủ đề được thảo luận nhiều nhất vẫn chính là kết cục của bộ truyện sẽ đi về đâu. Ai thực chất là nhân vật cuối cùng của toàn bộ câu chuyện?</b> </p><p>Gần đây, một người dùng Reddit có tên \"gohdroger\" đã làm xôn xao cộng đồng mạng khi đặt ra một giả thuyết mà subreddit One Piece đã cấm tài khoản này vì \"spoil truyện\". Tuy nhiên, phía \"gohdroger\" lên tiếng, anh chỉ đang viết giả thuyết chứ không có sự liên quan gì đến tác giả hay nhân viên của One Piece. Mặc dù vậy, người hâm mộ vẫn cho rằng có một sự liên quan nhất định nào đó.</p><p><br></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/fd9709a3e8ce5eaa_da728fb008a13fb8_8923216748280164185710.jpg\" style data-filename=\"filename\"></p><p><br></p><p>Tóm tắt phần kết thúc của \"gohdroger\" viết, như sau:</p><p style=\"margin-left: 25px;\">Khi Luffy lần đầu gặp Dyras (Joyboy), cậu đã xin lỗi nhưng chẳng rõ lý do, chính điều này đã tạo nên tiền đề những bí ẩn dần được hé mở. Im, một nhân vật bí ẩn đuổi theo Shanks Tóc Đỏ nhằm chiếm lấy Mũ Rơm, đây là một nhân vật giữ vai trò quan trọng trong lịch sử của toàn bộ câu chuyện.</p><p style=\"margin-left: 25px;\">Trong khoảng chương 1100(+/-), Luffy sẽ quay ngược về quá khứ 900 năm 9 tháng trước và gặp hai người anh em. Việc du hành thời gian của Luffy đã được thực hiện với sự giúp đỡ của ba trái ác quỷ là trái của Luffy, của Franky và của Bonney. Trái ác quỷ của Franky là trái mà anh đã lấy từ Kuma, người đã chết để cứu Bonney. Tại đây, Luffy đã gặp được hai người anh em, người anh là Thái tử Im và người em là Hoàng tử Dyras (Joyboy sau này). Dyras còn được biết đến với cái tên là \"con khỉ\", trong khi đó, Im lại là một người cực kỳ khôn ngoan. Im đã bí mật hợp tác cùng người ngoài (tổng cộng đến từ 20 quốc gia) để dàn dựng một cuộc đảo chính nhằm giành lấy ngôi vương vì anh đã nhận ra Dyras là người thừa kế tiếp theo.</p><p style=\"margin-left: 25px;\"><br></p><p style=\"margin-left: 25px;\"><img src=\"https://s199.imacdn.com/ta/2023/01/27/ff54968831a1e0b1_09649106da338fe3_10752916748285797185710.jpg\" style data-filename=\"filename\"></p><p style=\"margin-left: 25px;\"><br></p><p style=\"margin-left: 25px;\">Nguồn gốc của tất cả trái ác quỷ cũng đã được hé lộ khi sở hữu nguyên bản từ bốn phân loại tồn tại trên thế giới bao gồm: Thái Dương Thần, Khí Thần, Thổ Thần và Vũ Thần. Monkey D. Dragon, cha của Luffy đang sở hữu trái ác quỷ Vũ Thần và Vegapunk đã gợi ý về việc tạo ra trái ác quỷ dựa trên mong muốn của loài người. Khả năng duy nhất của Râu Đen để chiếm hữu nhiều trái ác quỷ được giải thích là do hắn có nhiều trái tim. Người sở hữu trái Thổ Thần là đồng minh của Im.&nbsp;</p><p style=\"margin-left: 25px;\">Các vũ khí cổ đại và câu chuyện bi thảm của Đô đốc Akainu cũng được hé lộ. Cuộc chiến giữa băng hải tặc Râu Đen và Tóc Đỏ, với nhiều người tử trận và trận quyết đấu cuối cùng là giữa Luffy và Râu Đen trong thế giới giấc mơ và dẫn đến việc Râu Đen ngủ vĩnh hằng. Enel cũng đã xuất hiện gặp gỡ Luffy cùng Dragon. Sau đó, băng hải tặc mũ rơm đã đến đảo Rockstar để chứng kiến gương mặt của Im, một tên đảo chính.</p><p style=\"margin-left: 25px;\"><br></p><p style=\"margin-left: 25px;\"><img src=\"https://s199.imacdn.com/ta/2023/01/27/c0189a0f45a6da1c_0bc32ad407906879_11742016748291841185710.jpg\" style data-filename=\"filename\"></p><p style=\"margin-left: 25px;\"><br></p><p>Một số người hâm mộ đã cho rằng \"gohdroger\" là người thân của Eiichiro Oda, tác giả bộ truyện One Piece vì những giả thuyết mà tài khoản bí ẩn này đặt ra rất phù hợp những diễn biến trong tương lai. Tuy nhiên, các bài đăng sau đó đều bị xóa khỏi nền tảng Reddit.</p><p>Trước khi tiết lộ nội dung, \"gohdroger\" cũng đã khẳng định từ chối trách nhiệm đối với khán giả khi đọc những gì mà mình viết.</p><p><br></p><p><i>Nội dung trong bài viết mang tính chất giả thuyết.</i></p><p><br></p>\n                                                    </p>\n                                                    \n                                                    \n\n\n\n			</div>', 'gia-thuyet-ve-kich-ban-ket-thuc-cua-one-piece-khien-netizen-nao-loan', 'https://tinanime.com/gia-thuyet-ve-kich-ban-ket-thuc-cua-one-piece-khien-netizen-nao-loan', '2023-02-07 16:41:16', '2023-02-07 16:41:16');
INSERT INTO `news` VALUES (4, 'Top 20 bộ anime có lượt xem cao nhất trên VuiGhe.Net trong năm 2022!', 'https://s199.imacdn.com/ta/2023/01/28/629a767700e1a4b3_7aebd12c2392a2be_7953416749238569185710.jpg', NULL, '<div class=\"news-content\">\n				                                                                                                                <p><b>Kỳ nghỉ lễ Tết Nguyên Đán 2023 cũng đang dần khép lại để bắt đầu những hành trình trong năm mới nhưng trước khi thực hiện những việc đó thì còn chần chừ gì mà không cùng TinAnime tổng kết lại năm vừa rồi chứ nhỉ? Vượt qua những cái tên tuổi lớn, nhiều tân binh anime đã bắt đầu chễm chệ giành lấy những vị trí cao trên bảng xếp hạng lượt xem của năm trên VuiGhe.Net. Bạn thử đoán xem, ai sẽ giành lấy vị trí quán quân?</b></p><p><br></p><p><b><span style=\"font-size: 16px;\">20. Arifureta Shokugyou de Sekai Saikyou</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/27/e8cf8357fd834db7_c131fd37136058d9_13463016748299146185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/arifureta-shokugyou-de-sekai-saikyou\" target=\"_blank\">https://vuighe.net/arifureta-shokugyou-de-sekai-saikyou</a></p><p><br></p><p><b><span style=\"font-size: 16px;\">19. Hunter X Hunter</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/8512ab00cf96b512_6262101aa35ff746_17669316749225524185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/hunter-x-hunter\" target=\"_blank\">https://vuighe.net/hunter-x-hunter</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">18. Kage no Jitsuryokusha ni Naritakute!</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/791000cd04f19517_e09f70c2b8134c87_10772016749226149185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/kage-no-jitsuryokusha-ni-naritakute\" target=\"_blank\">https://vuighe.net/kage-no-jitsuryokusha-ni-naritakute</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">17. Dấu Ấn Rồng Thiêng (2020)</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/4f1c98f34087a795_14cdde9a5ad756ba_16392416749227046185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/dau-an-rong-thieng-2020\" target=\"_blank\">https://vuighe.net/dau-an-rong-thieng-2020</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">16. Crayon Shin-chan Movie</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/7cea9df000c60788_014279137e80e630_18990716749227574185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/crayon-shin-chan-movie\" target=\"_blank\">https://vuighe.net/crayon-shin-chan-movie</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">15. Kimetsu no Yaiba (Lồng tiếng)</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/eaa74d6253b07cc9_f94c44742e5f5add_15709716749228171185710.jpg\" data-filename=\"filename\" style></p><p>Anime: <a href=\"https://vuighe.net/long-tieng-kimetsu-no-yaiba\" target=\"_blank\">https://vuighe.net/long-tieng-kimetsu-no-yaiba</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">14. Ousama Ranking&nbsp;</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/70f0b3492fa8109d_06eac17b384e32e4_11007916749228721185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/ousama-ranking\" target=\"_blank\">https://vuighe.net/ousama-ranking</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">13. Sono Bisque Doll wa Koi wo Suru</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/f71b1b7de673b27e_6586092702254b8c_9886416749232856185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/sono-bisque-doll-wa-koi-wo-suru\" target=\"_blank\">https://vuighe.net/sono-bisque-doll-wa-koi-wo-suru</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">12. Blue Lock</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/5624bd26df1b7e4a_abffc41c2a184a9e_13368416749233284185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/blue-lock\" target=\"_blank\">https://vuighe.net/blue-lock</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">11. Gotoubun no Hanayome</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/b79d88c8b5be584a_d1aebca8c7d1fcae_16372116749234012185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/gotoubun-no-hanayome\" target=\"_blank\">https://vuighe.net/gotoubun-no-hanayome</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">10. Overlord</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/91924c7fbf166d2d_e7b14182756a8392_20478216749234223185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/overlord\" target=\"_blank\">https://vuighe.net/overlord</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">9. Hội Pháp Sư</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/8a7e667d219bd851_c85b7b2387fd1af5_18123916749234559185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/hoi-phap-su\" target=\"_blank\">https://vuighe.net/hoi-phap-su</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">8. Naruto Shippuuden</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/5eff7d485904c6ae_808ad118b5e367e5_14404516749234745185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/naruto-shippuuden\" target=\"_blank\">https://vuighe.net/naruto-shippuuden</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">7. Spy x Family</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/271948759e822b2c_f7f0368ae5d0cedf_11068116749235046185710.jpg\" data-filename=\"filename\" style></p><p>Anime: <a href=\"https://vuighe.net/spy-x-family\" target=\"_blank\">https://vuighe.net/spy-x-family</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">6. Sứ Mạng Thần Chết</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/2eec2930cca12404_db3610ee805809cc_6418716749235929185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/su-mang-than-chet\" target=\"_blank\">https://vuighe.net/su-mang-than-chet</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">5. Kimetsu no Yaiba</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/27a007fdca1ea92f_77cc60d8543644e8_10036916749236107185710.jpg\" data-filename=\"filename\" style></p><p>Anime: <a href=\"https://vuighe.net/kimetsu-no-yaiba\" target=\"_blank\">https://vuighe.net/kimetsu-no-yaiba</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">4. World Trigger</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/596a00078788a651_3ecae88cb74266a5_16141616749236412185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/world-trigger\" target=\"_blank\">https://vuighe.net/world-trigger</a>&nbsp;</p><p><br></p><p><span style=\"font-size: 16px;\"><b>3. Boruto: Naruto Next Generations</b></span></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/c01461e0b35a7174_59ef86118fc915e9_14184116749237378185710.jpg\" style data-filename=\"filename\"></p><p>Anime: <a href=\"https://vuighe.net/boruto-naruto-next-generations\" target=\"_blank\">https://vuighe.net/boruto-naruto-next-generations</a>&nbsp;</p><p><br></p><p><span style=\"font-size: 16px;\"><b>2. Conan The Movie</b></span></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/c7320e99d025c258_e242bc5f2c9e40b8_18594716749237785185710.jpg\" style></p><p>Anime: <a href=\"https://vuighe.net/conan-the-movie\" target=\"_blank\">https://vuighe.net/conan-the-movie</a>&nbsp;</p><p><br></p><p><b><span style=\"font-size: 16px;\">1. Chainsaw Man</span></b></p><p><img src=\"https://s199.imacdn.com/ta/2023/01/28/068ce3a1fb8cc2af_f9696ef321970d4d_10597716749237991185710.jpg\" style></p><p>Anime: <a href=\"https://vuighe.net/chainsaw-man\" target=\"_blank\">https://vuighe.net/chainsaw-man</a>&nbsp;</p><p><br></p>\n                                                    \n                                                    \n\n\n\n			</div>', 'top-20-bo-anime-co-luot-xem-cao-nhat-tren-vuighenet-trong-nam-2022', 'https://tinanime.com/top-20-bo-anime-co-luot-xem-cao-nhat-tren-vuighenet-trong-nam-2022', '2023-02-07 16:41:16', '2023-02-07 16:41:16');
INSERT INTO `news` VALUES (5, 'Anime Corner công bố các hạng mục và gọi tên \"Anime của năm\" 2022!', 'https://s199.imacdn.com/ta/2023/01/28/8904c8db67e98d49_3966859022f3781c_6864816749240779185710.jpg', NULL, '<div class=\"news-content\">\n				                                                        <p><b>Anime Corner, một trong những trang tin tức hàng đầu về anime/manga đã công bố những cái tên chính thức cho \"Anime của năm\" đồng thời cùng những hạng mục nhỏ khác. Thống kê đã được thực hiện dựa trên 100.000 người hâm mộ. Hãy cùng TinAnime đón xem những bộ anime yêu thích của bạn có được điểm tên trong danh sách hay không nhé!</b></p><p><br></p><p style=\"text-align: center; \">&nbsp; &nbsp;<b><span style=\"font-size: 16px;\"> <span style=\"font-size: 21px;\">HẠNG MỤC THEO THỂ LOẠI</span></span></b></p><p style=\"text-align: center;\"><span style=\"font-size: 16px;\"><b>﻿ANIME CHUYỂN THỂ XUẤT SẮC NHẤT</b></span><b><br></b></p><p style=\"text-align: center;\">Bleach: Thousand-Year Blood War</p><p style=\"text-align: center; \"><img src=\"https://s199.imacdn.com/ta/2023/01/28/f936883310c0f8a9_78fa48eeb307a8c1_7571016749243938185710.jpg\" style data-filename=\"filename\"></p><p style=\"text-align: center; \">Anime: <a href=\"https://vuighe.net/su-mang-than-chet\" target=\"_blank\">https://vuighe.net/su-mang-than-chet</a></p><p style=\"text-align: center; \"><br></p><p style=\"text-align: center; \"><b><span style=\"font-size: 16px;\">DIỄN HỌA XUẤT SẮC NHẤT</span></b></p><p style=\"text-align: center; \">Demon Slayer: Kimetsu no Yaiba – Entertainment District Arc</p><p style=\"text-align: center; \"><img src=\"https://s199.imacdn.com/ta/2023/01/28/f927bb8cb88d67a9_82b2f84d5fc659ec_15283516749244935185710.jpg\" style data-filename=\"filename\"></p><p style=\"text-align: center; \">Anime: <a href=\"https://vuighe.net/kimetsu-no-yaiba\" target=\"_blank\">https://vuighe.net/kimetsu-no-yaiba</a>&nbsp;</p><p style=\"text-align: center; \"><br></p><p style=\"text-align: center; \"><b><span style=\"font-size: 16px;\">ANIME GIẢ TƯỞNG XUẤT SẮC NHẤT</span></b></p><p style=\"text-align: center; \">Kage no Jitsuryokusha ni Naritakute!</p><p style=\"text-align: center; \"><img src=\"https://s199.imacdn.com/ta/2023/01/28/15624fd25a7cd92d_69425faaaf6f881c_6923016749245588185710.jpg\" style data-filename=\"filename\"></p><p style=\"text-align: center; \">Anime: <a href=\"https://vuighe.net/kage-no-jitsuryokusha-ni-naritakute\" target=\"_blank\">https://vuighe.net/kage-no-jitsuryokusha-ni-naritakute</a></p><p style=\"text-align: center; \"><br></p><p style=\"text-align: center; \"><b><span style=\"font-size: 16px;\">ANIME BÍ ẨN/KỊCH TÍNH XUẤT SẮC NHẤT</span></b></p><p style=\"text-align: center; \">Youkoso Jitsuryoku Shijou Shugi no Kyoushitsu e 2nd Season</p><p style=\"text-align: center; \"><img src=\"https://s199.imacdn.com/ta/2023/01/28/190aea526397420d_7e55fea58130e8da_10886716749246557185710.jpg\" style data-filename=\"filename\"></p><p style=\"text-align: center; \">Anime: <a href=\"https://vuighe.net/youkoso-jitsuryoku-shijou-shugi-no-kyoushitsu-e\" target=\"_blank\">https://vuighe.net/youkoso-jitsuryoku-shijou-shugi-no-kyoushitsu-e</a>&nbsp;</p><p style=\"text-align: center; \"><br></p><p style=\"text-align: center; \"><b><span style=\"font-size: 16px;\">KHOA HỌC VIỄN TƯỞNG XUẤT SẮC NHẤT</span></b></p><p style=\"text-align: center; \">Cyberpunk: Edgerunners</p><p style=\"text-align: center; \"><img src=\"https://s199.imacdn.com/ta/2023/01/28/d31c0e9655bef9bc_bce42685dcd22810_10387416749246994185710.jpg\" style data-filename=\"filename\"></p><p style=\"text-align: center; \">Anime: <a href=\"https://vuighe.net/cyberpunk-edgerunners\" target=\"_blank\">https://vuighe.net/cyberpunk-edgerunners</a>&nbsp;</p><p style=\"text-align: center; \"><br></p><p style=\"text-align: center; \"><b><span style=\"font-size: 16px;\">ANIME HÀI HƯỚC XUẤT SẮC NHẤT</span></b></p><p style=\"text-align: center; \">SPY x FAMILY</p><p style=\"text-align: center; \